  1	import * as React from 'react';
  2	import { Alert, Button, AlertActionCloseButton } from '@patternfly/react-core';
  3	import cx from 'classnames';
  4	import { useField, useFormikContext, FormikValues } from 'formik';
  5	import * as _ from 'lodash';
  6	import { useTranslation } from 'react-i18next';
  7	import RadioGroupField from './RadioGroupField';
  8	import { EditorType } from './types';
  9	import { safeJSToYAML, safeYAMLToJS } from './yaml';
 10	
 11	import './SyncedEditorField.scss';
 12	import { LOCAL_STORAGE_KEY_EDITOR_TYPE } from './const';
 13	
 14	type FormErrorCallback<ReturnValue = {}> = () => ReturnValue;
 15	type WithOrWithoutPromise<Type> = Promise<Type> | Type;
 16	export type SanitizeToForm<YAMLStruct = {}, FormOutput = {}> = (
 17	  preFormData: YAMLStruct,
 18	) => WithOrWithoutPromise<FormOutput | FormErrorCallback<FormOutput>>;
 19	export type SanitizeToYAML = (preFormData: string) => string;
 20	
 21	type EditorContext<SanitizeTo> = {
 22	  name: string;
 23	  editor: React.ReactNode;
 24	  isDisabled?: boolean;
 25	  sanitizeTo?: SanitizeTo;
 26	  label?: string;
 27	};
 28	
 29	type SyncedEditorFieldProps = {
 30	  name: string;
 31	  formContext: EditorContext<SanitizeToForm>;
 32	  yamlContext: EditorContext<SanitizeToYAML>;
 33	  lastViewUserSettingKey: string;
 34	  prune?: (data: any) => any;
 35	  noMargin?: boolean;
 36	};
 37	
 38	const SyncedEditorField: React.FC<SyncedEditorFieldProps> = ({
 39	  name,
 40	  formContext,
 41	  yamlContext,
 42	  prune,
 43	  noMargin = false,
 44	}) => {
 45	  const { t } = useTranslation('plugin__pipelines-console-plugin');
 46	  const [editorType, setEditorType] = React.useState<EditorType>(
 47	    (localStorage.getItem(LOCAL_STORAGE_KEY_EDITOR_TYPE) as EditorType) ||
 48	      EditorType.Form,
 49	  );
 50	  const [field] = useField(name);
 51	
 52	  const { values, setFieldValue, setStatus } = useFormikContext<FormikValues>();
 53	
 54	  const formData = _.get(values, formContext.name);
 55	  const yamlData: string = _.get(values, yamlContext.name);
 56	
 57	  const [yamlWarning, setYAMLWarning] = React.useState<boolean>(false);
 58	  const [sanitizeToCallback, setSanitizeToCallback] =
 59	    React.useState<FormErrorCallback>(undefined);
 60	  const [disabledFormAlert, setDisabledFormAlert] = React.useState<boolean>(
 61	    formContext.isDisabled,
 62	  );
 63	
 64	  const changeEditorType = (newType: EditorType) => {
 65	    setEditorType(newType);
 66	    localStorage.setItem(LOCAL_STORAGE_KEY_EDITOR_TYPE, newType);
 67	    setFieldValue(name, newType);
 68	  };
 69	
 70	  const handleToggleToForm = async () => {
 71	    // Convert from YAML
 72	    let content = safeYAMLToJS(yamlData);
 73	
 74	    // Sanitize the YAML structure if possible
 75	    if (!_.isEmpty(content)) {
 76	      if (formContext.sanitizeTo) {
 77	        try {
 78	          content = await formContext.sanitizeTo(content);
 79	        } catch (e) {
 80	          // Failed to sanitize, discard invalid data
 81	          content = null;
 82	        }
 83	      }
 84	
 85	      // Handle sanitized result
 86	      if (typeof content === 'object' && !_.isEmpty(content)) {
 87	        setFieldValue(formContext.name, content);
 88	        changeEditorType(EditorType.Form);
 89	        return;
 90	      }
 91	      if (typeof content === 'function') {
 92	        setSanitizeToCallback(() => content);
 93	      }
 94	    }
 95	
 96	    setYAMLWarning(true);
 97	  };
 98	
 99	  const handleToggleToYAML = () => {
100	    const newYAML = safeJSToYAML(prune?.(formData) ?? formData, yamlData, {
101	      skipInvalid: true,
102	    });
103	    setFieldValue(
104	      yamlContext.name,
105	      yamlContext.sanitizeTo ? yamlContext.sanitizeTo(newYAML) : newYAML,
106	    );
107	    changeEditorType(EditorType.YAML);
108	  };
109	
110	  const onClickYAMLWarningConfirm = async () => {
111	    setYAMLWarning(false);
112	    if (sanitizeToCallback) {
113	      setFieldValue(formContext.name, sanitizeToCallback());
114	    }
115	    changeEditorType(EditorType.Form);
116	  };
117	
118	  const onClickYAMLWarningCancel = () => {
119	    setYAMLWarning(false);
120	  };
121	
122	  const onChangeType = (newType: EditorType) => {
123	    switch (newType) {
124	      case EditorType.YAML:
125	        handleToggleToYAML();
126	        break;
127	      case EditorType.Form:
128	        handleToggleToForm();
129	        break;
130	      default:
131	        break;
132	    }
133	    setStatus({ submitError: '' });
134	  };
135	
136	  React.useEffect(() => {
137	    setDisabledFormAlert(formContext.isDisabled);
138	    if (field.value !== editorType) {
139	      setFieldValue(name, editorType);
140	    }
141	  }, [editorType, field.value, formContext.isDisabled, name, setFieldValue]);
142	
143	  React.useEffect(() => {
144	    // Sync formData when yamlData changes (while in YAML mode)
145	    if (editorType === EditorType.YAML && yamlData) {
146	      const syncFormDataFromYaml = async () => {
147	        try {
148	          const content = safeYAMLToJS(yamlData);
149	          if (!_.isEmpty(content) && formContext.sanitizeTo) {
150	            const sanitizedContent = await formContext.sanitizeTo(content);
151	            if (
152	              typeof sanitizedContent === 'object' &&
153	              !_.isEmpty(sanitizedContent)
154	            ) {
155	              // Only update if the content is different
156	              if (!_.isEqual(sanitizedContent, formData)) {
157	                setFieldValue(formContext.name, sanitizedContent);
158	              }
159	            }
160	          }
161	        } catch (e) {
162	          console.warn('Failed to sync form data from YAML', e);
163	        }
164	      };
165	      syncFormDataFromYaml();
166	    }
167	  }, [
168	    yamlData,
169	    editorType,
170	    formContext.sanitizeTo,
171	    formContext.name,
172	    setFieldValue,
173	    formData,
174	  ]);
175	
176	  return (
177	    <>
178	      <div
179	        className={cx('ocs-synced-editor-field__editor-toggle', {
180	          margin: !noMargin,
181	        })}
182	        data-test="synced-editor-field"
183	      >
184	        <RadioGroupField
185	          label={t('Configure via:')}
186	          name={name}
187	          options={[
188	            {
189	              label: formContext.label || t('Form view'),
190	              value: EditorType.Form,
191	              isDisabled: formContext.isDisabled,
192	            },
193	            {
194	              label: yamlContext.label || t('YAML view'),
195	              value: EditorType.YAML,
196	              isDisabled: yamlContext.isDisabled,
197	            },
198	          ]}
199	          onChange={(val: string) => onChangeType(val as EditorType)}
200	          isInline
201	        />
202	      </div>
203	      {yamlWarning && (
204	        <Alert
205	          className="co-synced-editor__yaml-warning"
206	          variant="danger"
207	          isInline
208	          title={t('Invalid YAML cannot be persisted')}
209	        >
210	          <p>{t('Switching to form view will delete any invalid YAML.')}</p>
211	          <Button variant="danger" onClick={onClickYAMLWarningConfirm}>
212	            {t('Switch and delete')}
213	          </Button>
214	          &nbsp;
215	          <Button variant="secondary" onClick={onClickYAMLWarningCancel}>
216	            {t('Cancel')}
217	          </Button>
218	        </Alert>
219	      )}
220	      {disabledFormAlert && (
221	        <Alert
222	          variant="custom"
223	          title={t(
224	            'Form view is disabled for this chart because the schema is not available',
225	          )}
226	          actionClose={
227	            <AlertActionCloseButton
228	              onClose={() => setDisabledFormAlert(false)}
229	            />
230	          }
231	          isInline
232	        />
233	      )}
234	      {editorType === EditorType.Form && !disabledFormAlert
235	        ? formContext.editor
236	        : yamlContext.editor}
237	    </>
238	  );
239	};
240	
241	export default SyncedEditorField;

